class Solution {
    public int longestPalindrome(String s, String t) {
        String combined = s + t;
        int maxLen = 0;
        for (int i = 0; i < combined.length(); i++) {
            int len1 = expandAroundCenter(combined, i, i);
            int len2 = expandAroundCenter(combined, i, i + 1);
            maxLen = Math.max(maxLen, Math.max(len1, len2));
        }
        return maxLen;
    }

    private int expandAroundCenter(String s, int left, int right) {
        while (left >= 0 && right < s.length() && s.charAt(left) == s.charAt(right)) {
            if (isFromDifferentStrings(s, left, right)) {
                return right - left + 1;
            }
            left--;
            right++;
        }
        return 1;
    }

    private boolean isFromDifferentStrings(String s, int left, int right) {
        String s1 = s.substring(0, s.length() / 2);
        String s2 = s.substring(s.length() / 2);
        return (left < s1.length() && right >= s1.length()) || (right < s1.length() && left >= s1.length());
    }
}

